        eTGForexReportTmp.MovementDuringThePeriod   =  (eTGForexReportTmp.ClosingUnrealised) + (eTGForexReportTmp.RealisedExGainAndLoss);
        eTGForexReportTmp.insert();
    }
}

public void getSalesData()
{
    CustTrans                   custTrans,custtransInvoice,custtransSettleEx,custTransSameVoucher;
    CustSettlement              custSettlement;
    CustTransOpen               custTransOpen;

    this.insOpencustTrans();

    while select custTrans
        order by TransDate asc
            where custTrans.TransDate       >= fromDate
               && custTrans.TransDate       <= toDate
               && custTrans.CurrencyCode    != ledger.AccountingCurrency
               && (custTrans.TransType != LedgerTransType::Settlement
               || (custTrans.TransType == LedgerTransType::Settlement  && custTrans.AmountCur >  0))
    {
        eTGForexReportTmp.clear();
        this.inscustTrans(custTrans);

        if(custTrans.TransType == LedgerTransType::Settlement )
        {
            eTGForexReportTmp.SettlementDate          = custTrans.LastSettleDate;
            eTGForexReportTmp.SettlementRate          = custTrans.displayAccountingExchangeRate();
            eTGForexReportTmp.SettlementAmount        = custTrans.AmountCur;

            select firstonly CurrencyCode,ExchRate from custtransSettleEx
                where custtransSettleEx.Invoice == custTrans.Invoice
                && custtransSettleEx.TransType == LedgerTransType::Sales
                || custtransSettleEx.TransType == LedgerTransType::Cust;

            eTGForexReportTmp.PeriodBeginningExRate     = custtransSettleEx.displayAccountingExchangeRate();
        }
        else
        {
            eTGForexReportTmp.TransactionExchnageRate   = custTrans.displayAccountingExchangeRate();
            eTGForexReportTmp.TransactionAmount         = custTrans.AmountCur;
            eTGForexReportTmp.PeriodBeginningExRate     = custTrans.displayAccountingExchangeRate();
        }

        this.getDefaultDimensionValue(custTrans.DefaultDimension);

        eTGForexReportTmp.PeriodClosingExRate = this.getExchangeRate(toDate,custTrans.CurrencyCode,ledger.AccountingCurrency);

        if(!eTGForexReportTmp.PeriodClosingExRate)
            eTGForexReportTmp.PeriodClosingExRate = this.getExchangeRate(toDate,ledger.AccountingCurrency,custTrans.CurrencyCode,NoYes::Yes);

        if(eTGForexReportTmp.SettlementRate)
            eTGForexReportTmp.RealisedExGainAndLoss =  ((eTGForexReportTmp.PeriodBeginningExRate - eTGForexReportTmp.SettlementRate)*(eTGForexReportTmp.SettlementAmount));

        //else
        //    eTGForexReportTmp.ClosingUnrealised = (eTGForexReportTmp.BalanceAmount) * (eTGForexReportTmp.PeriodClosingExRate - eTGForexReportTmp.TransactionExchnageRate);

        if(custTrans.TransType == LedgerTransType::Payment )
        {
            select firstonly SettlementVoucher from custSettlement
                where custSettlement.OffsetTransVoucher == custTrans.Voucher
            join Invoice from custtransInvoice
                where custtransInvoice.Voucher == custSettlement.SettlementVoucher;

            eTGForexReportTmp.Invoice = custtransInvoice.Invoice;
        }

        eTGForexReportTmp.MovementDuringThePeriod   =  (eTGForexReportTmp.ClosingUnrealised) + (eTGForexReportTmp.RealisedExGainAndLoss);

        if(custTrans.TransType == LedgerTransType::ExchAdjustment)
          //  && custTrans.AmountMST < 0)
        {
            select firstonly RecId from custTransSameVoucher
                where custTransSameVoucher.Voucher == custTrans.Voucher
                    && custTransSameVoucher.TransType == LedgerTransType::Settlement;

            if(!custTransSameVoucher)
            {
                eTGForexReportTmp.ClosingUnrealised         = this.getUnrealizedAmt(custTrans.Voucher,custTrans.AmountMST);
                eTGForexReportTmp.MovementDuringThePeriod   =  (eTGForexReportTmp.ClosingUnrealised) + (eTGForexReportTmp.RealisedExGainAndLoss);
                eTGForexReportTmp.insert();
            }
        }

        else if(custTrans.TransType != LedgerTransType::ExchAdjustment)
            eTGForexReportTmp.insert();
    }
}
